    // ---------------------------------------------------------------------------
    // resolve_rtk_state
    // ---------------------------------------------------------------------------

    #[test]
    fn resolve_rtk_state_no_binary() {
        let state = resolve_rtk_state();
        // If rtk is not installed, path is None and version_ok is false
        if state.path.is_none() {
            assert!(!state.version_ok);
            assert!(!state.is_available());
        }
    }

    #[test]
    fn resolve_rtk_state_consistent() {
        let state = resolve_rtk_state();
        // version_ok should always be false when path is None
        assert_eq!(state.path.is_none(), !state.version_ok || state.path.is_none());
    }

