    #[tokio::test]
    async fn rewrite_command_creates_db_directory() {
        let tmp = TempDir::new().unwrap();
        let db_dir = tmp.path().join("rtk_db");
        assert!(!db_dir.exists());

        let _ = rewrite_command(
            &PathBuf::from("/nonexistent/rtk"),
            &db_dir,
            "echo hello",
        )
        .await;

        assert!(db_dir.exists());
        assert!(db_dir.is_dir());
    }

